#!/usr/bin/env node
// agentify:managed
// Executes trusted argv-vector checks under the single draft deadline. Raw output is never persisted.
import { execFileSync } from "node:child_process";
import * as fs from "node:fs";
import * as path from "node:path";
import { assertBeforeStep, readJson, runDeadlineProcess, writeAtomic } from "./draft-run-control.mjs";
const [repoArg, baseArg, configArg, stateArg, outputArg] = process.argv.slice(2);
if (!repoArg || !baseArg || !configArg || !stateArg || !outputArg) throw new Error("usage: validate-draft-run.mjs REPO BASE CONFIG DRAFT_RUN_STATE OUTPUT");
const root = fs.realpathSync(repoArg); const config = readJson(path.resolve(root, configArg), "draft configuration"); const stateFile = path.resolve(stateArg); const state = readJson(stateFile, "draft run state");
if (config.mode !== "draft" || !Array.isArray(config.validation_checks) || config.validation_checks.length === 0) throw new Error("structured validation policy is unavailable");
assertBeforeStep(state, "structured validation"); writeAtomic(stateFile, state);
const base = execFileSync("git", ["-C", root, "rev-parse", baseArg], { encoding: "utf8" }).trim(); const head = execFileSync("git", ["-C", root, "rev-parse", "HEAD"], { encoding: "utf8" }).trim();
const changed = execFileSync("git", ["-C", root, "diff", "--name-only", `${base}...${head}`], { encoding: "utf8" }).trim().split("\n").filter(Boolean).sort();
const worktreeStatus = () => execFileSync("git", ["-C", root, "status", "--porcelain=v1", "--untracked-files=all"], { encoding: "utf8" }).trim().split("\n").filter(Boolean).filter((line) => line.slice(3) !== ".agentify-runtime" && !line.slice(3).startsWith(".agentify-runtime/"));
const statusBeforeChecks = worktreeStatus(); const forbidden = Array.isArray(config.forbidden_paths) ? config.forbidden_paths : [".github/workflows", ".git", ".agentify"];
const forbiddenChanges = changed.filter((file) => forbidden.some((prefix) => file === prefix || file.startsWith(`${prefix}/`))); const dependencyFiles = new Set(["package.json", "package-lock.json", "npm-shrinkwrap.json", "pnpm-lock.yaml", "yarn.lock", "bun.lock", "requirements.txt", "pyproject.toml", "poetry.lock", "go.mod", "go.sum", "Cargo.toml", "Cargo.lock"]); const dependencyChanges = changed.filter((file) => dependencyFiles.has(file) || [...dependencyFiles].some((name) => file.endsWith(`/${name}`)));
const checks = []; const requiredKinds = ["build", "tests", "typecheck", "lint", "security"];
for (const check of config.validation_checks) {
  if (!check || typeof check.name !== "string" || !requiredKinds.includes(check.kind) || !Array.isArray(check.argv) || check.argv.length === 0 || check.argv.some((arg) => typeof arg !== "string" || !arg || /[\r\n\0]/.test(arg))) throw new Error("validation check configuration is invalid");
  const started = Date.now(); let result;
  try { result = await runDeadlineProcess(stateFile, state, `validation ${check.kind}`, check.argv[0], check.argv.slice(1), { cwd: root, env: { ...process.env, GH_TOKEN: undefined, GITHUB_TOKEN: undefined, AGENT_PAT: undefined }, stdio: "ignore", graceMs: 2000, timeoutMs: Number(check.timeout_ms ?? 600000) }); checks.push({ name: check.name.slice(0, 120), kind: check.kind, status: result.code === 0 ? "passed" : "failed", exit_code: result.code, runtime_ms: Date.now() - started, output_tail: "Command output omitted from persisted evidence to prevent secret leakage." }); }
  catch (error) { const message = error instanceof Error ? error.message : ""; checks.push({ name: check.name.slice(0, 120), kind: check.kind, status: state.runtime.cancellation_requested_at ? "runtime_limit_cancelled" : message.includes("process timeout") ? "timeout" : "failed", exit_code: null, runtime_ms: Date.now() - started, output_tail: "Command output omitted from persisted evidence to prevent secret leakage." }); if (state.runtime.cancellation_requested_at) break; }
}
for (const kind of requiredKinds) if (!checks.some((check) => check.kind === kind)) checks.push({ name: `${kind} policy`, kind, status: "missing", exit_code: null, runtime_ms: 0, output_tail: "Required structured check is not configured." });
const headAfterChecks = execFileSync("git", ["-C", root, "rev-parse", "HEAD"], { encoding: "utf8" }).trim(); const statusAfterChecks = worktreeStatus();
const configuredState = path.resolve(root, config.state_dir ?? ".agents/agentify"); const allowedStateRoots = [".agents/agentify", ".claude/agentify", ".pi/agentify"].map((item) => path.resolve(root, item)); if (!allowedStateRoots.includes(configuredState)) throw new Error("validation state directory is outside supported Agentify roots");
const manifestPath = path.join(configuredState, "manifest.json"); const manifest = fs.existsSync(manifestPath) ? readJson(manifestPath, "managed manifest") : { files: [] }; const managed = new Set(Array.isArray(manifest.files) ? manifest.files.map((entry) => typeof entry === "string" ? entry : entry.path).filter(Boolean) : []); const generatedOwnershipFailures = changed.filter((file) => /^(?:\.agents|\.claude|\.codex|\.pi)\//.test(file) && !managed.has(file));
const runtimeMs = Math.max(0, Date.now() - Date.parse(state.runtime.started_at)); const costEligible = state.budget_usd === Number(config.maximum_cost_usd) && state.cost_limit_status === "within_limit" && (!state.require_measured_cost || state.cost_measurement_status === "measured");
const policyChecks = { forbidden_paths: forbiddenChanges.length === 0, dependency_changes: config.allow_dependency_changes === true || dependencyChanges.length === 0, generated_file_ownership: generatedOwnershipFailures.length === 0, diff_nonempty: changed.length > 0, validation_head_unchanged: headAfterChecks === head, validation_worktree_unchanged: JSON.stringify(statusAfterChecks) === JSON.stringify(statusBeforeChecks), cost: costEligible, runtime: !state.runtime.cancellation_requested_at && runtimeMs <= Number(config.maximum_runtime_ms) };
const checksPassed = checks.every((check) => check.status === "passed"); const safetyPolicyPassed = Object.values(policyChecks).every(Boolean); const passed = checksPassed && safetyPolicyPassed; const failedDraftPolicyUsed = !checksPassed && safetyPolicyPassed && config.allow_failed_draft === true;
const report = { schema_version: "1", base_commit: base, head_commit: head, files_changed: changed, validation_results: checks, diff_policy: policyChecks, forbidden_path_changes: forbiddenChanges, dependency_changes: dependencyChanges, generated_ownership_failures: generatedOwnershipFailures, validation_status_before: statusBeforeChecks, validation_status_after: statusAfterChecks, budget_usd: state.budget_usd, reserved_cost_usd: state.reserved_cost_usd, measured_cost_usd: state.measured_cost_usd, estimated_cost_usd: state.estimated_cost_usd, remaining_budget_usd: state.remaining_budget_usd, cost_measurement_status: state.cost_measurement_status, cost_limit_status: state.cost_limit_status, pricing_policy_version: state.pricing_policy_version, model_calls: state.model_calls, runtime_ms: runtimeMs, runtime: state.runtime, retries: 0, passed, publication_allowed: passed || failedDraftPolicyUsed, failed_draft_policy_used: failedDraftPolicyUsed };
fs.writeFileSync(path.resolve(outputArg), `${JSON.stringify(report, null, 2)}\n`, { mode: 0o600 }); if (!report.publication_allowed) process.exitCode = 1;
